example.code:
// Type-level: all usages of SharedService will preserve reference
[FastClonerBehavior(CloneBehavior.Reference)]
public class SharedService { }

// Member-level: override behavior for specific members
public class MyClass
{
    [FastClonerBehavior(CloneBehavior.Ignore)]
    public CancellationToken Token { get; set; }  // Set to default
}

// Type-level: all usages of SharedService will preserve reference
[FastClonerBehavior(CloneBehavior.Reference)]
public class SharedService { }

// Member-level: override behavior for specific members
public class MyClass
{
    [FastClonerBehavior(CloneBehavior.Ignore)]
    public CancellationToken Token { get; set; }  // Set to default
}

// Type-level: all usages of CancellationToken get default value
[FastClonerIgnore]
public struct MyCancellationWrapper { }

// Member-level
public class MyClass
{
    [FastClonerIgnore]
    public CancellationToken Token { get; set; }
}

// Type-level: all usages of ILogger preserve reference
[FastClonerReference]
public class LoggerService : ILogger { }

// Member-level: only this property preserves reference
public class MyClass
{
    [FastClonerReference]
    public ILogger Logger { get; set; }
}

// Type-level: shallow clone the entire Config type
[FastClonerShallow]
public class Config { }

// Member-level: shallow clone only this member
public class Node
{
    [FastClonerShallow]
    public ParentObject Parent { get; set; }
}

private readonly object _mutex = new object();
public void DoStuff()
{
    lock (_mutex)
    {
        Thread.Sleep(TimeSpan.FromSeconds(1));
    }
}

private readonly AsyncLock _mutex = new AsyncLock();
public async Task DoStuffAsync()
{
    using (await _mutex.LockAsync())
    {
        await Task.Delay(TimeSpan.FromSeconds(1));
    }
}
